const STORAGE_KEY = "notepad-content";
const STORAGE_TIME_KEY = "notepad-saved-at";
const ON_CONTENT_RESTORED = "OnContentRestored";

let dotNetRef;
let beforeUnloadHandler;

export function initialize(ref) {
    dotNetRef = ref;

    const content = localStorage.getItem(STORAGE_KEY) || "";
    const savedAt = localStorage.getItem(STORAGE_TIME_KEY) || "";

    try {
        dotNetRef.invokeMethodAsync(ON_CONTENT_RESTORED, content, savedAt);
    } catch { /* circuit disconnected */ }
}

export function save(content) {
    const now = new Date().toLocaleTimeString([], {
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
    });
    localStorage.setItem(STORAGE_KEY, content);
    localStorage.setItem(STORAGE_TIME_KEY, now);
    return now;
}

export function clear() {
    localStorage.removeItem(STORAGE_KEY);
    localStorage.removeItem(STORAGE_TIME_KEY);
}

export function enableBeforeUnload() {
    if (beforeUnloadHandler) return;
    beforeUnloadHandler = (e) => { e.preventDefault(); };
    window.addEventListener("beforeunload", beforeUnloadHandler);
}

export function disableBeforeUnload() {
    if (!beforeUnloadHandler) return;
    window.removeEventListener("beforeunload", beforeUnloadHandler);
    beforeUnloadHandler = null;
}

export function dispose() {
    disableBeforeUnload();
    dotNetRef = null;
}

