    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public NotepadInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    public async ValueTask InitializeAsync<T>(DotNetObjectReference<T> dotNetRef) where T : class
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(InitMethod, dotNetRef);
    }

    public async ValueTask<string> SaveAsync(string content)
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<string>(SaveMethod, content);
    }

    public async ValueTask ClearAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(ClearMethod);
    }

    public async ValueTask EnableBeforeUnloadAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(EnableBeforeUnloadMethod);
    }

    public async ValueTask DisableBeforeUnloadAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(DisableBeforeUnloadMethod);
    }

