namespace sv_a5173694967945edbceeb5605a4f2fa8.Components.Pages;

public sealed class NotepadInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/Pages/Notepad.razor.js";
    internal const string InitMethod = "initialize";
    internal const string SaveMethod = "save";
    internal const string ClearMethod = "clear";
    internal const string EnableBeforeUnloadMethod = "enableBeforeUnload";
    internal const string DisableBeforeUnloadMethod = "disableBeforeUnload";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public NotepadInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

