@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="_content" @bind:event="oninput"
          @bind:after="OnContentChanged" placeholder="Type your notes here…"></textarea>

<div class="d-flex align-items-center gap-2 mb-3">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (_lastSavedAt is not null)
    {
        <span class="text-muted ms-2">Last saved at @_lastSavedAt</span>
    }
</div>

@code {
    private string _content = string.Empty;
    private string? _lastSavedAt;
    private string _savedContent = string.Empty;
    private bool _hasUnsavedChanges;
    private NotepadInterop? _interop;
    private DotNetObjectReference<Notepad>? _dotNetRef;
    private Timer? _autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            _dotNetRef = DotNetObjectReference.Create(this);
            await _interop.InitializeAsync(_dotNetRef);

            _autoSaveTimer = new Timer(AutoSaveCallback, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    [JSInvokable]
    public async Task OnContentRestored(string content, string savedAt)
    {
        await InvokeAsync(() =>
        {
            _content = content;
            _savedContent = content;
            _lastSavedAt = string.IsNullOrEmpty(savedAt) ? null : savedAt;
            StateHasChanged();
        });
    }

    private async Task OnContentChanged()
    {
        var dirty = _content != _savedContent;
        if (dirty != _hasUnsavedChanges)
        {
            _hasUnsavedChanges = dirty;
            if (_interop is not null)
            {
                if (_hasUnsavedChanges)
                    await _interop.EnableBeforeUnloadAsync();
                else
                    await _interop.DisableBeforeUnloadAsync();
            }
        }
    }

    private async Task SaveNowAsync()
    {
        if (_interop is null) return;
        _lastSavedAt = await _interop.SaveAsync(_content);
        _savedContent = _content;

        if (_hasUnsavedChanges)
        {
            _hasUnsavedChanges = false;
            await _interop.DisableBeforeUnloadAsync();
        }
    }

    private async Task ClearAsync()
    {
        if (_interop is null) return;
        _content = string.Empty;
        _savedContent = string.Empty;
        _lastSavedAt = null;
        await _interop.ClearAsync();

        if (_hasUnsavedChanges)
        {
            _hasUnsavedChanges = false;
            await _interop.DisableBeforeUnloadAsync();
        }
    }

    private async void AutoSaveCallback(object? state)
    {
        if (_interop is null || !_hasUnsavedChanges) return;

        await InvokeAsync(async () =>
        {
            await SaveNowAsync();
            StateHasChanged();
        });
    }

    public async ValueTask DisposeAsync()
    {
        if (_autoSaveTimer is not null)
            await _autoSaveTimer.DisposeAsync();

        if (_interop is not null)
            await _interop.DisposeAsync();

        _dotNetRef?.Dispose();
    }
}

